import{_ as a,o as t,c as i,ae as n}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"Link Templates","description":"","frontmatter":{"title":"Link Templates","slug":"link-templates"},"headers":[],"relativePath":"marketer-hub/link-templates.md","filePath":"marketer-hub/link-templates.md"}'),l={name:"marketer-hub/link-templates.md"};function r(o,e,s,h,p,d){return t(),i("div",null,[...e[0]||(e[0]=[n('<div class="info custom-block"><p class="custom-block-title">Attention</p><p>Learn more about Branch’s new <a href="https://help.branch.io/docs/links-page" target="_blank" rel="noreferrer">Links Page</a>, which contains an enhanced interface that will help you build, manage, and deploy links at scale.</p></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><a href="https://dashboard.branch.io/quick-links/link-templates/" target="_blank" rel="noreferrer">Link Templates</a> is a tab in the LinkHub page of the Branch Dashboard and is automatically included as part of Branch&#39;s <a href="./linkhub.html">LinkHub</a> product. It allows you to manage all of the templates that your Short Links may be using. A Link Template can be applied when creating a Short Link to auto-apply reusable attributes that can be used on multiple Short Links. Applying a Link Template to your Short Link has many benefits and can save you time when managing your Branch-powered campaigns.</p><h4 id="benefits-of-link-templates" tabindex="-1">Benefits of Link Templates <a class="header-anchor" href="#benefits-of-link-templates" aria-label="Permalink to &quot;Benefits of Link Templates&quot;">​</a></h4><ul><li>Reusable templates</li><li>Avoid creating duplicate links</li><li>Create links with just one click</li><li>Pre-populate values for cleaner analytics</li></ul><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><p>Your Branch Account requires permission to the Link Templates feature via the <strong>Link Template Settings Permission</strong>. This can be set on each individual by an admin in your Branch Dashboard&#39;s <a href="https://dashboard.branch.io/account-settings/team" target="_blank" rel="noreferrer">Team Member Settings</a>.</p><p>“Admin” and “Team Member” users will get View &amp; Edit access to Link Templates automatically. “Full Read” will get View access. “Limited Read” and “User Coordinator” will not get any access.</p><table tabindex="0"><thead><tr><th>Permission</th><th>Details</th></tr></thead><tbody><tr><td>View</td><td>Ability for the user to use and access existing Link Templates.</td></tr><tr><td>Edit</td><td>Ability for the user to create, edit, archive, and duplicate Link Templates.</td></tr></tbody></table><p>Additional details on setting permissions for users on the Branch Dashboard can be found <a href="./add-manage-users-roles-permissions-access.html">here</a>.</p><h2 id="create-link-template" tabindex="-1">Create Link Template <a class="header-anchor" href="#create-link-template" aria-label="Permalink to &quot;Create Link Template&quot;">​</a></h2><p>To create a Link Template, navigate to the Link Template tab from the LinkHub page in the Branch Dashboard. Alternatively, if you have not created a Link Template before, you will have the option to create a Link Template when creating a Branch Short Link.</p><p>Click <strong>Create New Template</strong>.</p><h3 id="_1-name-link-template" tabindex="-1">1. Name Link Template <a class="header-anchor" href="#_1-name-link-template" aria-label="Permalink to &quot;1. Name Link Template&quot;">​</a></h3><p>The first and required step is to name your Link Template. Make sure to make the name of your template descriptive as it will make it easy to remember and apply the template for future Short Links along with additional details about the template in the Link Template Note section.</p><p>Below the Link Template Note section, you can mark specific field names to be <strong>Required</strong>. checking the respective checkbox for a given field name will enforce the user to fill out values for those fields when the template is applied to a Short Link.</p><h3 id="_2-analytics-tags" tabindex="-1">2. Analytics Tags <a class="header-anchor" href="#_2-analytics-tags" aria-label="Permalink to &quot;2. Analytics Tags&quot;">​</a></h3><p>Adding analytics tags to your Link Template is optional. We recommend adding analytics tags so that your Dashboard Reports all use the same standard naming conventions for tracking campaign performance. These fields can also be marked as <strong>Required</strong>.</p><h3 id="_3-redirects" tabindex="-1">3. Redirects <a class="header-anchor" href="#_3-redirects" aria-label="Permalink to &quot;3. Redirects&quot;">​</a></h3><p>Adding redirects to your Link Template is optional. You can specific redirects by platform. Doing so will determine the user experience when clicking on the link without the app installed to route the user to the app store, a web page, or a deep view. These fields will always be marked as <strong>Required</strong>.</p><p>Setting the <strong>Redirect Type</strong> to <em>Default</em> will use the settings set on the <a href="./configure-default-link-behaviors.html">App Settings</a> page.</p><h3 id="_4-link-data" tabindex="-1">4. Link Data <a class="header-anchor" href="#_4-link-data" aria-label="Permalink to &quot;4. Link Data&quot;">​</a></h3><p>Adding link data to your Link Template is optional. You can add fields that will be useful for the mobile app (ex. <a href="./deep-link-data-options.html#deep-link-data-key-values">deep linking parameters</a>). You may need to reach out to your mobile development team to confirm with key/value pairs are necessary for your link based on your use case. These fields can also be marked as <strong>Required</strong>.</p><h3 id="_5-social-media-tags" tabindex="-1">5. Social Media Tags <a class="header-anchor" href="#_5-social-media-tags" aria-label="Permalink to &quot;5. Social Media Tags&quot;">​</a></h3><p>Adding social media tags to your Link Template is optional. These tags can be set in order to fill Open Graph tags that make your Short Link more descriptive with a title, description, and image.</p><p>If you set a fixed value for the Original Web URL field in the Name Link Template step, links created from this template will scrape that URL for open graph tags to fill the social media tags.</p><h2 id="manage-link-templates" tabindex="-1">Manage Link Templates <a class="header-anchor" href="#manage-link-templates" aria-label="Permalink to &quot;Manage Link Templates&quot;">​</a></h2><p>If you&#39;ve created any Link Templates, you can view and manage them all on the <a href="https://dashboard.branch.io/quick-links/link-templates" target="_blank" rel="noreferrer">Link Templates</a> tab.</p><h4 id="link-template-actions" tabindex="-1">Link Template Actions <a class="header-anchor" href="#link-template-actions" aria-label="Permalink to &quot;Link Template Actions&quot;">​</a></h4><p>For each Link Template, you can perform a specific action:</p><ul><li><p>Edit Template: This action will allow you to edit the template.</p><ul><li>Editing a template will not retroactively change Short Links that have already been made using the template.</li></ul></li><li><p>Create Link from Template: This action will allow you to create a Short Link with the template applied to it.</p></li><li><p>Archive Template: This action will remove the delete the LInk Template. <strong>Archiving does not impact existing Short Links using the template.</strong></p></li><li><p>Duplicate Template: This action will create a copy of the template and let you change the copied Link Template&#39;s attributes.</p></li></ul>',31)])])}const u=a(l,[["render",r]]);export{m as __pageData,u as default};
